function calcularFactorial(numero: number): number {
    /**
     * Calcula el factorial de un número.
     * 
     * @param numero El número para el cual se calculará el factorial.
     * @returns El factorial del número de entrada.
     */
    if (!Number.isInteger(numero)) {
        throw new Error('El número de entrada debe ser un entero');
    }

    if (numero < 0) {
        throw new Error('El número de entrada no puede ser negativo');
    }

    let resultado = 1;
    for (let i = 2; i <= numero; i++) {
        resultado *= i;
    }

    return resultado;
}

function calcularFactorialValidado(numero: number): number {
    try {
        return calcularFactorial(numero);
    } catch (error) {
        if (error instanceof Error) {
            throw new Error(`Error al calcular factorial: ${error.message}`);
        } else {
            throw error;
        }
    }
}

export { calcularFactorialValidado };
