function generarSaludo(nombre: string): string {
    if (nombre === null || nombre === undefined) {
        throw new Error('El nombre no puede ser nulo');
    }
    if (typeof nombre !== 'string') {
        throw new Error('El nombre debe ser una cadena de texto');
    }
    if (nombre.trim() === '') {
        throw new Error('El nombre no puede estar vacío');
    }
    return `Hola, ${nombre}!`;
}

function main(nombre: string): string {
    try {
        const saludo = generarSaludo(nombre);
        return saludo;
    } catch (error) {
        if (error instanceof Error) {
            return `Error: ${error.message}`;
        } else {
            return 'Error desconocido';
        }
    }
}

export { main };
